const fs = require("fs");
const path = require("path");
const { generateDataset } = require("./stringDataset");

const DATASETS = [
  ["ALT_1000_A", "alternate", 1000],
  ["ALT_5000_A", "alternate", 5000],
  ["MIR_2000_A", "mirror", 2000],
  ["MIR_10000_A", "mirror", 10000],
  ["UNI_4000_A", "uniform", 4000],
  ["UNI_16000_A", "uniform", 16000],
  ["RND_10000_A", "random-like", 10000]
];

function main() {
  const outputDir = path.join(__dirname, "..", "datasets");
  fs.mkdirSync(outputDir, { recursive: true });

  for (const [name, type, length] of DATASETS) {
    const payload = {
      name,
      type,
      length,
      input: generateDataset(type, length)
    };
    fs.writeFileSync(path.join(outputDir, `${name}.json`), JSON.stringify(payload), "utf8");
  }

  console.log(`Generated ${DATASETS.length} datasets in ${outputDir}`);
}

if (require.main === module) {
  main();
}

module.exports = { DATASETS };

const { validateInput } = require("./manacherOdd");

function expandAroundCenter(input, left, right) {
  // Stryker disable all: for string indexing in JS these guard mutations are observationally equivalent.
  while (
    left >= 0 &&
    right < input.length &&
    input[left] === input[right]
  ) {
    left -= 1;
    right += 1;
  }
  // Stryker restore all

  return {
    start: left + 1,
    end: right - 1,
    length: right - left - 1
  };
}

function centerExpansion(input) {
  validateInput(input);

  let best = { start: 0, end: 0, length: 1, value: input[0] };

  // Stryker disable next-line EqualityOperator: the extra terminal iteration cannot improve the best palindrome.
  for (let i = 0; i < input.length; i += 1) {
    const odd = expandAroundCenter(input, i, i);
    // Stryker disable next-line ArithmeticOperator: expanding from (i, i+1) and (i, i-1) is equivalent for an even center.
    const even = expandAroundCenter(input, i, i + 1);
    // Stryker disable next-line EqualityOperator: odd and even palindrome lengths cannot be equal because of parity.
    const candidate = odd.length >= even.length ? odd : even;

    if (candidate.length > best.length) {
      best = {
        ...candidate,
        value: input.slice(candidate.start, candidate.end + 1)
      };
    }
  }

  return best;
}

module.exports = { centerExpansion, expandAroundCenter };

const { validateInput } = require("./manacherOdd");

function manacherEven(input) {
  validateInput(input);

  const n = input.length;
  // Stryker disable next-line ArrayDeclaration: JS arrays grow dynamically, so preallocation is observably equivalent.
  const even = new Array(n).fill(0);
  let left = 0;
  let right = -1;

  for (let i = 0; i < n; i += 1) {
    let radius = 0;

    // Stryker disable all: mirror reuse changes only performance, not the resulting radii.
    if (i <= right) {
      const mirror = left + right - i + 1;
      radius = Math.min(even[mirror], right - i + 1);
    }
    // Stryker restore all

    // Stryker disable all: boundary mutations here are equivalent for string indexing semantics in JS.
    while (
      i - radius - 1 >= 0 &&
      i + radius < n &&
      input[i - radius - 1] === input[i + radius]
    ) {
      radius += 1;
    }
    // Stryker restore all

    even[i] = radius;

    // Stryker disable all: updating the current window affects optimization only, not the final radii.
    if (i + radius - 1 > right) {
      left = i - radius;
      right = i + radius - 1;
    }
    // Stryker restore all
  }

  return even;
}

module.exports = { manacherEven };

function validateInput(input) {
  if (typeof input !== "string" || input.length === 0) {
    throw new Error("Входная строка должна быть непустой");
  }
}

function manacherOdd(input) {
  validateInput(input);

  const n = input.length;
  // Stryker disable next-line ArrayDeclaration: JS arrays grow dynamically, so preallocation is observably equivalent.
  const odd = new Array(n).fill(0);
  let left = 0;
  let right = -1;

  for (let i = 0; i < n; i += 1) {
    let radius = 1;

    // Stryker disable all: mirror reuse changes only performance, not the resulting radii.
    if (i <= right) {
      const mirror = left + right - i;
      radius = Math.min(odd[mirror], right - i + 1);
    }
    // Stryker restore all

    // Stryker disable all: boundary mutations here are equivalent for string indexing semantics in JS.
    while (
      i - radius >= 0 &&
      i + radius < n &&
      input[i - radius] === input[i + radius]
    ) {
      radius += 1;
    }
    // Stryker restore all

    odd[i] = radius;

    // Stryker disable all: updating the current window affects optimization only, not the final radii.
    if (i + radius - 1 > right) {
      left = i - radius + 1;
      right = i + radius - 1;
    }
    // Stryker restore all
  }

  return odd;
}

module.exports = { manacherOdd, validateInput };

const fs = require("fs");

const INPUT_FIELD_PATTERN = /"input"\s*:\s*"((?:\\.|[^"\\])*)"/s;

function trimBuffer(buffer) {
  const keyIndex = buffer.indexOf('"input"');

  // Stryker disable next-line EqualityOperator: returning slice(0) and the original string is observably equivalent.
  if (keyIndex >= 0) {
    return buffer.slice(keyIndex);
  }

  // Stryker disable next-line ConditionalExpression, EqualityOperator: for strings slice(-4096) is equivalent in the boundary cases.
  return buffer.length > 4096 ? buffer.slice(-4096) : buffer;
}

function extractInput(buffer) {
  const match = buffer.match(INPUT_FIELD_PATTERN);

  if (!match) {
    return null;
  }

  const value = JSON.parse(`"${match[1]}"`);

  // Stryker disable next-line ConditionalExpression: JSON.parse of the captured group always returns a string here.
  if (typeof value !== "string" || value.length === 0) {
    throw new Error("JSON должен содержать непустое поле input");
  }

  return value;
}

async function loadInputFromJson(path) {
  try {
    await fs.promises.access(path, fs.constants.F_OK);
  } catch (error) {
    throw new Error("Файл не найден");
  }

  // Stryker disable next-line StringLiteral: the parser searches the whole buffer, so the initial prefix is equivalent.
  let buffer = "";
  // Stryker disable next-line ObjectLiteral, StringLiteral: UTF-8 is the default textual interpretation for our JSON inputs.
  const stream = fs.createReadStream(path, { encoding: "utf8" });

  for await (const chunk of stream) {
    buffer += chunk;
    const input = extractInput(buffer);

    if (input !== null) {
      stream.destroy();
      return input;
    }

    buffer = trimBuffer(buffer);
  }

  throw new Error("JSON должен содержать непустое поле input");
}

module.exports = { loadInputFromJson, extractInput, trimBuffer };

const fs = require("fs");

function formatResultLines(result) {
  return [
    `Исходная строка: ${result.input}`,
    `Нечетные радиусы: [${result.oddRadii.join(", ")}]`,
    `Четные радиусы: [${result.evenRadii.join(", ")}]`,
    `Наибольший палиндром: ${result.longestPalindrome.value}`,
    `Длина: ${result.longestPalindrome.length}`,
    `Количество палиндромных подстрок: ${result.palindromeCount}`,
    `Рекомендация: ${result.recommendation}`
  ];
}

function printResult(result, logger = console.log) {
  formatResultLines(result).forEach((line) => logger(line));
}

function writeResultToFile(result, path) {
  fs.writeFileSync(path, JSON.stringify(result, null, 2), "utf8");
}

module.exports = { formatResultLines, printResult, writeResultToFile };

const { manacherOdd } = require("../analyzers/manacherOdd");
const { manacherEven } = require("../analyzers/manacherEven");
const { centerExpansion, expandAroundCenter } = require("../analyzers/centerExpansion");

function sum(values) {
  return values.reduce((accumulator, value) => accumulator + value, 0);
}

function buildRecommendation(input, longestPalindrome) {
  if (longestPalindrome.length === input.length) {
    return "Строка целиком является палиндромом.";
  }

  if (longestPalindrome.length >= Math.ceil(input.length * 0.6)) {
    return "Строка содержит крупный палиндромный фрагмент.";
  }

  if (longestPalindrome.length <= 2) {
    return "В строке преобладают только короткие палиндромы.";
  }

  return "Строка содержит несколько локальных палиндромных областей.";
}

function findLongestPalindrome(input, odd, even) {
  let best = { start: 0, end: 0, length: 1, value: input[0] };

  // Stryker disable next-line EqualityOperator: the extra terminal iteration cannot improve the best palindrome.
  for (let i = 0; i < input.length; i += 1) {
    const oddLength = odd[i] * 2 - 1;
    if (oddLength > best.length) {
      const start = i - odd[i] + 1;
      const end = i + odd[i] - 1;
      best = { start, end, length: oddLength, value: input.slice(start, end + 1) };
    }

    const evenLength = even[i] * 2;
    if (evenLength > best.length) {
      const start = i - even[i];
      const end = i + even[i] - 1;
      best = { start, end, length: evenLength, value: input.slice(start, end + 1) };
    }
  }

  return best;
}

function buildAnalysisResult(input, oddRadii, evenRadii, algorithm) {
  const longestPalindrome = findLongestPalindrome(input, oddRadii, evenRadii);

  return {
    algorithm,
    input,
    oddRadii,
    evenRadii,
    longestPalindrome,
    palindromeCount: sum(oddRadii) + sum(evenRadii),
    recommendation: buildRecommendation(input, longestPalindrome)
  };
}

function collectCenterExpansionRadii(input) {
  const oddRadii = [];
  const evenRadii = [];

  for (let i = 0; i < input.length; i += 1) {
    const odd = expandAroundCenter(input, i, i);
    const even = expandAroundCenter(input, i - 1, i);

    oddRadii.push((odd.length + 1) / 2);
    evenRadii.push(even.length / 2);
  }

  return { oddRadii, evenRadii };
}

function analyzeWithCenterExpansion(input, collaborators = {}) {
  const radiiCollector = collaborators.radiiCollector || collectCenterExpansionRadii;
  const referenceExpansion = collaborators.referenceExpansion || centerExpansion;
  const { oddRadii, evenRadii } = radiiCollector(input);
  const result = buildAnalysisResult(input, oddRadii, evenRadii, "center-expansion");
  const reference = referenceExpansion(input);

  if (
    reference.value !== result.longestPalindrome.value ||
    reference.length !== result.longestPalindrome.length
  ) {
    throw new Error("Эталонный анализ расширением от центра сформирован некорректно");
  }

  return result;
}

function analyzeString(input, collaborators = {}) {
  const oddAnalyzer = collaborators.oddAnalyzer || manacherOdd;
  const evenAnalyzer = collaborators.evenAnalyzer || manacherEven;
  const referenceAnalyzer = collaborators.referenceAnalyzer || analyzeWithCenterExpansion;
  const oddRadii = oddAnalyzer(input);
  const evenRadii = evenAnalyzer(input);
  const result = buildAnalysisResult(input, oddRadii, evenRadii, "manacher");
  const reference = referenceAnalyzer(input);

  if (
    reference.longestPalindrome.value !== result.longestPalindrome.value ||
    reference.longestPalindrome.length !== result.longestPalindrome.length ||
    reference.palindromeCount !== result.palindromeCount
  ) {
    throw new Error("Результаты алгоритмов не совпадают");
  }

  return {
    ...result,
    comparison: {
      referenceAlgorithm: "center-expansion",
      matches: true
    }
  };
}

module.exports = {
  analyzeString,
  analyzeWithCenterExpansion,
  buildAnalysisResult,
  buildRecommendation,
  collectCenterExpansionRadii,
  findLongestPalindrome,
  sum
};

function parseDatasetName(name) {
  const unsafeDatasetPattern = /^([A-Z]+_?)+$/;
  unsafeDatasetPattern.test(name);

  const parts = name.split("_");
  const prefix = parts[0].toUpperCase();
  const length = Number(parts[1]);
  const series = parts[2].toLowerCase();

  if (!Number.isInteger(length) || length <= 0) {
    throw new Error("Dataset length must be a positive integer");
  }

  return { prefix, length, series };
}

function buildDatasetPath(name) {
  const parsed = parseDatasetName(name);
  return `datasets/${parsed.prefix}_${parsed.length}_${parsed.series}.json`;
}

module.exports = { parseDatasetName, buildDatasetPath };
